<script>
var FILINGS={
pvt:[
{form:'AGM',desc:'Annual General Meeting',due:'2026-09-30',entity:['pvt'],penalty:'Non-holding: \u20B91L company + \u20B925K officer',cat:'roc'},
{form:'AOC-4',desc:'Financial Statements to ROC (within 30 days of AGM)',due:'2026-10-29',entity:['pvt','opc'],penalty:'2\u201310\u00D7 normal fee (\u20B9400\u20136,000)',cat:'roc'},
{form:'MGT-7A',desc:'Annual Return to ROC (within 60 days of AGM)',due:'2026-11-28',entity:['pvt','opc'],penalty:'2\u201310\u00D7 normal fee (\u20B9400\u20136,000)',cat:'roc'},
{form:'DIR-3 KYC',desc:'Director KYC verification (annual)',due:'2026-09-30',entity:['pvt','opc','llp'],penalty:'\u20B95,000 + DIN deactivation',cat:'roc'},
{form:'ADT-1',desc:'Auditor Appointment (within 15 days of AGM)',due:'2026-10-15',entity:['pvt','opc'],penalty:'\u20B9300/day (max \u20B912L)',cat:'roc'},
{form:'ITR-6',desc:'Income Tax Return (audit cases)',due:'2026-09-30',entity:['pvt','opc'],penalty:'\u20B95,000 or \u20B910,000 late fee',cat:'tax'},
{form:'GSTR-9',desc:'GST Annual Return (FY 2025-26)',due:'2026-12-31',entity:['pvt','opc','llp'],penalty:'\u20B9200/day (max 0.5% of turnover)',cat:'gst'},
{form:'TDS Q1',desc:'TDS Return (Apr\u2013Jun 2026)',due:'2026-07-31',entity:['pvt','opc','llp'],penalty:'\u20B9200/day under Sec 234E',cat:'tax'},
{form:'TDS Q2',desc:'TDS Return (Jul\u2013Sep 2026)',due:'2026-10-31',entity:['pvt','opc','llp'],penalty:'\u20B9200/day under Sec 234E',cat:'tax'},
{form:'TDS Q3',desc:'TDS Return (Oct\u2013Dec 2026)',due:'2027-01-31',entity:['pvt','opc','llp'],penalty:'\u20B9200/day under Sec 234E',cat:'tax'},
{form:'TDS Q4',desc:'TDS Return (Jan\u2013Mar 2027)',due:'2027-05-31',entity:['pvt','opc','llp'],penalty:'\u20B9200/day under Sec 234E',cat:'tax'}
],
llp:[
{form:'Form 11',desc:'LLP Annual Return',due:'2026-05-30',entity:['llp'],penalty:'\u20B9100/day (no cap)',cat:'roc'},
{form:'Form 8',desc:'Statement of Account & Solvency',due:'2026-10-30',entity:['llp'],penalty:'\u20B9100/day (no cap)',cat:'roc'},
{form:'DIR-3 KYC',desc:'Partner KYC verification (annual)',due:'2026-09-30',entity:['llp'],penalty:'\u20B95,000 + DPIN deactivation',cat:'roc'},
{form:'ITR-5',desc:'Income Tax Return (audit: Sep 30, non-audit: Jul 31)',due:'2026-09-30',entity:['llp'],penalty:'\u20B95,000 or \u20B910,000 late fee',cat:'tax'},
{form:'GSTR-9',desc:'GST Annual Return (FY 2025-26)',due:'2026-12-31',entity:['llp'],penalty:'\u20B9200/day (max 0.5% of turnover)',cat:'gst'}
]
};

function setEntity(el){document.querySelectorAll('.entity-chip').forEach(function(c){c.classList.remove('active');});el.classList.add('active');renderCalendar();}
function getEntity(){var a=document.querySelector('.entity-chip.active');return a?a.getAttribute('data-val'):'pvt';}
function setFilter(btn){document.querySelectorAll('.filter-btn').forEach(function(b){b.classList.remove('active');});btn.classList.add('active');renderCalendar();}
function getFilter(){var a=document.querySelector('.filter-btn.active');return a?a.getAttribute('data-val'):'all';}

function renderCalendar(){
var ent=getEntity(),filter=getFilter(),now=new Date();
var filings=ent==='llp'?FILINGS.llp:FILINGS.pvt.filter(function(f){return f.entity.indexOf(ent)!==-1;});
// Add LLP common filings for llp
if(ent!=='llp'){
FILINGS.llp.forEach(function(f){if(f.entity.indexOf(ent)!==-1&&!filings.find(function(x){return x.form===f.form&&x.due===f.due;}))filings.push(f);});
}
filings.sort(function(a,b){return new Date(a.due)-new Date(b.due);});
var grid=document.getElementById('calendarGrid');
var html='',counts={overdue:0,'due-soon':0,upcoming:0};
filings.forEach(function(f){
var due=new Date(f.due),diff=Math.ceil((due-now)/(1000*60*60*24));
var status,badge;
if(diff<0){status='overdue';badge='<span class="cal-badge red">Overdue '+Math.abs(diff)+'d</span>';counts.overdue++;}
else if(diff<=30){status='due-soon';badge='<span class="cal-badge amber">Due in '+diff+'d</span>';counts['due-soon']++;}
else{status='upcoming';badge='<span class="cal-badge green">'+diff+' days</span>';counts.upcoming++;}
if(filter!=='all'&&filter!==status)return;
html+='<div class="cal-card '+status+'"><div class="cal-hd"><span class="cal-form">'+f.form+'</span>'+badge+'</div><div class="cal-desc">'+f.desc+'</div><div class="cal-date">Due: '+due.toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})+'</div><div class="cal-penalty">\u26A0 Penalty: '+f.penalty+'</div></div>';
});
if(!html)html='<p style="color:var(--text-muted);padding:20px">No filings match this filter.</p>';
grid.innerHTML=html;
}

function buildFAQ(){var list=document.getElementById('faqList');FAQS.forEach(function(faq){var item=document.createElement('div');item.className='faq-item';item.innerHTML='<button class="faq-question" onclick="toggleFaq(this)"><span>'+faq.q+'</span><span class="faq-icon">+</span></button><div class="faq-answer"><div class="faq-answer-inner">'+faq.a+'</div></div>';list.appendChild(item);});}
function toggleFaq(btn){var item=btn.closest('.faq-item');var o=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');});if(!o)item.classList.add('open');}
var navLinks=document.querySelectorAll('.toc-nav a');window.addEventListener('scroll',function(){var cur='';document.querySelectorAll('[id]').forEach(function(s){if(pageYOffset>=s.offsetTop-80)cur=s.getAttribute('id');});navLinks.forEach(function(l){l.classList.toggle('active',l.getAttribute('href')==='#'+cur);});});

var FAQS=[
{q:"What are the ROC filing deadlines for Pvt Ltd?",a:"Private Limited Companies must file AOC-4 within 30 days of AGM which is typically by October 29 each year. MGT-7A annual return is due within 60 days of AGM usually by November 28. ITR-6 is due September 30 for audit cases. DIR-3 KYC must be filed by September 30 annually for all directors."},
{q:"What is the penalty for late ROC filing?",a:"Late filing attracts additional fees of 2 times normal fee for delay up to 30 days, 4 times for 30 to 60 days, 6 times for 60 to 90 days, and 10 times for delay beyond 90 days. For companies the normal AOC-4 fee ranges from 200 to 600 rupees so penalties can reach 2000 to 6000 rupees per form."},
{q:"What ROC filings are required for LLP?",a:"LLPs must file Form 8 Statement of Account and Solvency within 30 days from end of 6 months of financial year by October 30. Form 11 Annual Return is due within 60 days of financial year end by May 30. LLP ITR-5 is due September 30 if audit applicable otherwise July 31."},
{q:"What is DIR-3 KYC and when is it due?",a:"DIR-3 KYC is annual KYC verification for all directors and designated partners holding DIN or DPIN. Due date is September 30 every year. First-time filing uses DIR-3 KYC web form. Subsequent years use DIR-3 KYC-WEB. Penalty for non-filing is 5000 rupees and DIN gets deactivated until KYC is completed."},
{q:"When is AGM required to be held?",a:"First AGM must be held within 9 months of closing of first financial year. Subsequent AGMs within 6 months of financial year end which means by September 30 for March year-end companies. Gap between two AGMs cannot exceed 15 months. OPC is exempt from holding AGM."},
{q:"What is the due date for statutory audit?",a:"Statutory audit must be completed before the AGM. Practically auditors complete the audit by August to September to allow time for AGM preparation. Tax audit report under Section 44AB is due September 30. Companies must appoint auditor at each AGM for a term of 5 years."},
{q:"What happens if company does not file annual returns?",a:"Non-filing for 3 or more consecutive years leads to company being struck off from ROC records under Section 248. Directors of struck-off companies are disqualified from being appointed as director in any company for 5 years. Additionally the company loses its legal status and bank accounts may be frozen."},
{q:"What are the quarterly compliance requirements?",a:"Companies must hold at least one board meeting per quarter with gap not exceeding 120 days between two meetings. TDS returns are due quarterly by July 31, October 31, January 31, and May 31. GST returns GSTR-1 and GSTR-3B are due monthly or quarterly depending on turnover."},
{q:"When is GSTR-9 annual return due?",a:"GSTR-9 annual return is due by December 31 of the following financial year. For FY 2024-25 the due date is December 31 2025. GSTR-9C reconciliation statement is required if turnover exceeds 5 crore. Businesses with turnover up to 2 crore are exempt from filing GSTR-9."},
{q:"What is the due date for income tax return?",a:"Companies and firms requiring audit must file by September 30. Companies with transfer pricing applicability file by November 30. Non-audit cases file by July 31. Belated return can be filed by December 31 with penalty. Revised return deadline is also December 31 of the assessment year."},
{q:"Can ROC filing deadlines be extended?",a:"MCA occasionally extends deadlines through special notifications especially during COVID-type situations or portal technical issues. Companies can also apply for extension of AGM date under Section 96 through ROC. However regular compliance deadlines generally cannot be extended for individual companies."},
{q:"What is the cost of annual ROC compliance?",a:"MCA filing fees range from 200 to 3600 rupees per form depending on authorized capital. Professional fees for CA or CS to handle annual compliance range from 15000 to 50000 for small companies. Total annual compliance cost including audit ITR and ROC is typically 30000 to 100000 for small Pvt Ltd companies."},
{q:"What filings are needed for newly incorporated companies?",a:"New companies must file INC-20A Commencement of Business within 180 days of incorporation. First auditor appointment via ADT-1 within 15 days of AGM. First board meeting within 30 days of incorporation. DIR-3 KYC for all directors. GST registration if applicable. These are in addition to regular annual filings."}
];
document.addEventListener('DOMContentLoaded',function(){buildFAQ();renderCalendar();});
</script>
